const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const actorType = clean(b.actor_type) || 'system';
const actorId = clean(b.actor_id) || 'unknown';
const action = clean(b.action);
const resourceType = clean(b.resource_type) || 'generic';
const resourceId = clean(b.resource_id) || 'n/a';
const metadata = b.metadata && typeof b.metadata === 'object' ? b.metadata : {};
const valid = action !== '';
return [{json:{
  valid,
  error: valid ? '' : 'action es requerido',
  actor_type: actorType,
  actor_id: actorId,
  action,
  resource_type: resourceType,
  resource_id: resourceId,
  metadata
}}];
